def count_valid_permutations(s: str) -> int:
    n = len(s)
    MOD = 10**9 + 7
    dp = [[0] * (n + 1) for _ in range(n + 1)]

    for i in range(n + 1):
        dp[i][i] = 1

    for len in range(1, n + 1):
        for i in range(n - len + 1):
            j = i + len
            if s[i] == 'D':
                dp[i][j] = dp[i+1][j] * (j - i)
                dp[i][j] %= MOD
            if s[j-1] == 'I':
                dp[i][j] += dp[i][j-1] * (j - i)
                dp[i][j] %= MOD
            for k in range(i+1, j):
                if s[k-1] == 'D':
                    dp[i][j] -= dp[i][k-1] * dp[k][j]
                    dp[i][j] %= MOD
                else:
                    dp[i][j] += dp[i][k-1] * dp[k][j]
                    dp[i][j] %= MOD

